using System.ComponentModel.DataAnnotations;

namespace DocSummary.Models;

public class SummarizeRequest
{
    [Required]
    [MinLength(1)]
    public required string Text { get; set; }

    /// <summary>
    /// Maximum number of sentences to include in the summary. Defaults to 3.
    /// </summary>
    [Range(1, 50)]
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalSentenceCount { get; set; }
    public int SummarySentenceCount { get; set; }
}

namespace DocSummary.Services;

public interface ISummarizationService
{
    Models.SummarizeResponse Summarize(string text, int maxSentences);
}

using System.Text.RegularExpressions;
using DocSummary.Models;

namespace DocSummary.Services;

/// <summary>
/// Performs extractive summarization by scoring sentences based on word frequency
/// and returning the highest-scoring sentences in their original order.
/// </summary>
public partial class ExtractiveSummarizationService : ISummarizationService
{
    private static readonly HashSet<string> StopWords = new(StringComparer.OrdinalIgnoreCase)
    {
        "a", "an", "the", "and", "or", "but", "is", "are", "was", "were",
        "in", "on", "at", "to", "for", "of", "with", "by", "from", "it",
        "this", "that", "these", "those", "be", "been", "being", "have",
        "has", "had", "do", "does", "did", "will", "would", "could",
        "should", "may", "might", "shall", "can", "not", "no", "as", "if",
        "than", "so", "its", "he", "she", "we", "they", "i", "you", "me",
        "my", "your", "his", "her", "our", "their", "about", "up", "out",
        "just", "also", "very", "often", "however", "too", "then", "them"
    };

    public SummarizeResponse Summarize(string text, int maxSentences)
    {
        var sentences = SplitIntoSentences(text);

        if (sentences.Count <= maxSentences)
        {
            return new SummarizeResponse
            {
                Summary = string.Join(" ", sentences),
                OriginalSentenceCount = sentences.Count,
                SummarySentenceCount = sentences.Count
            };
        }

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var sentenceScores = ScoreSentences(sentences, wordFrequencies);

        // Pick top-scoring sentences but preserve original order
        var topIndices = sentenceScores
            .Select((score, index) => (score, index))
            .OrderByDescending(x => x.score)
            .Take(maxSentences)
            .Select(x => x.index)
            .Order()
            .ToList();

        var summarySentences = topIndices.Select(i => sentences[i]);

        return new SummarizeResponse
        {
            Summary = string.Join(" ", summarySentences),
            OriginalSentenceCount = sentences.Count,
            SummarySentenceCount = topIndices.Count
        };
    }

    private static List<string> SplitIntoSentences(string text)
    {
        return SentenceSplitter()
            .Split(text)
            .Select(s => s.Trim())
            .Where(s => s.Length > 0)
            .ToList();
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in Tokenize(sentence))
            {
                if (!StopWords.Contains(word) && word.Length > 1)
                {
                    frequencies[word] = frequencies.GetValueOrDefault(word) + 1;
                }
            }
        }

        return frequencies;
    }

    private static List<double> ScoreSentences(List<string> sentences, Dictionary<string, int> wordFrequencies)
    {
        int maxFreq = wordFrequencies.Values.DefaultIfEmpty(1).Max();
        var scores = new List<double>(sentences.Count);

        foreach (var sentence in sentences)
        {
            var words = Tokenize(sentence);
            if (words.Count == 0)
            {
                scores.Add(0);
                continue;
            }

            double score = words
                .Where(w => wordFrequencies.ContainsKey(w))
                .Sum(w => (double)wordFrequencies[w] / maxFreq);

            // Normalize by word count to avoid bias toward long sentences
            scores.Add(score / words.Count);
        }

        return scores;
    }

    private static List<string> Tokenize(string text)
    {
        return WordTokenizer()
            .Matches(text)
            .Select(m => m.Value.ToLowerInvariant())
            .ToList();
    }

    [GeneratedRegex(@"(?<=[.!?])\s+", RegexOptions.Compiled)]
    private static partial Regex SentenceSplitter();

    [GeneratedRegex(@"\b[a-zA-Z]+\b", RegexOptions.Compiled)]
    private static partial Regex WordTokenizer();
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController(ISummarizationService summarizationService) : ControllerBase
{
    [HttpPost]
    public ActionResult<SummarizeResponse> Summarize([FromBody] SummarizeRequest request)
    {
        var result = summarizationService.Summarize(request.Text, request.MaxSentences);
        return Ok(result);
    }
}

